from functools import partial, lru_cache, wraps

@lru_cache(maxsize=128)
def fibonacci(n):
    if n < 2:
        return n
    return fibonacci(n - 1) + fibonacci(n - 2)

def loglama(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        print(f"{func.__name__} cagrildi: args={args}")
        return func(*args, **kwargs)
    return wrapper

@loglama
def us_al(taban, us):
    return taban ** us

iki_uzerinden = partial(us_al, taban=2)

