import java.util.*;
import java.util.stream.*;

class Ogrenci {
    String isim; double not; String bolum;
    Ogrenci(String i, double n, String b) { isim=i; not=n; bolum=b; }
    public String getIsim() { return isim; }
    public double getNotOrtalamasi() { return not; }
    public String getBolum() { return bolum; }
}
class OgrenciDTO {
    String isim, bolum;
    OgrenciDTO(String i, String b) { isim=i; bolum=b; }
    public String toString() { return isim+" - "+bolum; }
}
public class Main {
    public static void main(String[] a) {
        List<Ogrenci> o = Arrays.asList(
            new Ogrenci("Ali",85.5,"Bilg. Muh."), new Ogrenci("Veli",45,"Elektrik"),
            new Ogrenci("Ayse",92.3,"Bilg. Muh."), new Ogrenci("Fatma",70.5,"Makine"),
            new Ogrenci("Mehmet",60,"Insaat"), new Ogrenci("Zeynep",88,"Endustri"));
        o.stream().filter(x->x.getNotOrtalamasi()>70)
            .sorted(Comparator.comparingDouble(Ogrenci::getNotOrtalamasi).reversed())
            .map(x->new OgrenciDTO(x.getIsim(),x.getBolum()))
            .collect(Collectors.toList())
            .forEach(System.out::println);
    }
}

import java.util.Optional;
class Adres { String sehir, ilce; Adres(String s, String i) { sehir=s; ilce=i; } public String getSehir() { return sehir; } }
class Kullanici { String isim; Adres adres; Kullanici(String i, Adres a) { isim=i; adres=a; } public Optional<Adres> getAdres() { return Optional.ofNullable(adres); } }
public class Main {
    public static void main(String[] a) {
        Kullanici k1 = new Kullanici("Ali", new Adres("Istanbul","Kadikoy"));
        Kullanici k2 = new Kullanici("Veli", null);
        Kullanici k3 = null;
        String s = Optional.ofNullable(k1).flatMap(Kullanici::getAdres).map(Adres::getSehir).orElse("Bilinmiyor");
        System.out.println("Sehir: "+s);
        try { Optional.ofNullable(k2).flatMap(Kullanici::getAdres).map(Adres::getSehir).orElseThrow(()->new RuntimeException("Adres yok")); }
        catch(Exception e) { System.out.println("Hata: "+e.getMessage()); }
        Optional.ofNullable(k3).ifPresentOrElse(k->System.out.println("Var"), ()->System.out.println("Null"));
        Optional.ofNullable(k1).flatMap(Kullanici::getAdres).filter(a->a.getSehir().equals("Istanbul")).ifPresent(a->System.out.println("Istanbul"));
    }
}

import java.util.concurrent.*;
import java.util.stream.*;
public class Main {
    public static void main(String[] args) throws Exception {
        CompletableFuture<Integer> s1 = CompletableFuture.supplyAsync(()->{ sleep(1000); return 250; });
        CompletableFuture<Integer> s2 = CompletableFuture.supplyAsync(()->{ sleep(1500); return 180; });
        CompletableFuture<Integer> s3 = CompletableFuture.supplyAsync(()->{ sleep(800); return 320; });
        CompletableFuture<Integer> t = CompletableFuture.allOf(s1,s2,s3)
            .thenApply(v->Stream.of(s1,s2,s3).map(CompletableFuture::join).mapToInt(Integer::intValue).sum());
        System.out.println("Toplam: "+t.get());
        CompletableFuture<String> h = CompletableFuture.supplyAsync(()->{ if(Math.random()>0.5) throw new RuntimeException("Hata"); return "OK"; })
            .exceptionally(e->"Hata: "+e.getMessage()).thenApply(x->"Sonuc: "+x);
        System.out.println(h.get());
        CompletableFuture<String> z = CompletableFuture.supplyAsync(()->"K-42").thenCompose(id->CompletableFuture.supplyAsync(()->id+" yuklendi"));
        System.out.println(z.get());
    }
    static void sleep(int m) { try { Thread.sleep(m); } catch(InterruptedException e){} }
}

