@FunctionalInterface
interface Donusturucu<T,R> { R donustur(T g); default Donusturucu<T,R> once(Consumer<T> i) { return t->{i.accept(t); return donustur(t);}; } }

public class Main {
    public static void main(String[] a) {
        Donusturucu<String,Integer> u = String::length;
        Donusturucu<String,String> b = String::toUpperCase;
        System.out.println(u.donustur("Merhaba")+" "+b.donustur("merhaba"));
        Consumer<String> y = System.out::println; y.accept("Consumer");
        Supplier<Double> r = Math::random; System.out.println("Rastgele: "+r.get());
        Function<Integer,Integer> kare = x->x*x, ikiEkle = x->x+2;
        System.out.println("5: "+kare.andThen(ikiEkle).apply(5));
        Predicate<Integer> cift = x->x%2==0;
        List<Integer> s = Arrays.asList(1,2,3,4,5,6);
        System.out.println("Cift: "+s.stream().filter(cift).collect(Collectors.toList()));
    }
}

import java.util.stream.*;
enum HaftalikMesai {
    PAZARTESI(8,Tip.TAM), SALI(8,Tip.TAM), CARSAMBA(8,Tip.TAM),
    PERSEMBE(8,Tip.TAM), CUMA(6,Tip.YARIM), CUMARTESI(0,Tip.TATIL), PAZAR(0,Tip.TATIL);
    enum Tip { TAM, YARIM, TATIL }
    private final int s; private final Tip t;
    HaftalikMesai(int s, Tip t) { this.s=s; this.t=t; }
    public int getS() { return s; } public Tip getT() { return t; }
    public double maas(int ucret) { return s*ucret; }
    public static int toplamSaat() { return Stream.of(values()).mapToInt(HaftalikMesai::getS).sum(); }
}
public class Main {
    public static void main(String[] a) {
        int u=150;
        Stream.of(HaftalikMesai.values()).forEach(g->System.out.printf("%s: %ds -> %.0f TL%n",g,g.getS(),g.maas(u)));
        System.out.println("Toplam saat: "+HaftalikMesai.toplamSaat());
        double t = Stream.of(HaftalikMesai.values()).mapToDouble(g->g.maas(u)).sum();
        System.out.println("Toplam maas: "+t);
    }
}

