package main
import (
	"bufio"
	"errors"
	"fmt"
	"os"
	"strconv"
	"strings"
)
type ParseError struct { Line int; Val string; Err error }
func (e *ParseError) Error() string { return fmt.Sprintf("satir %d: %s - %v", e.Line, e.Val, e.Err) }
func (e *ParseError) Unwrap() error { return e.Err }
func topla(path string) (int, error) {
	f, err := os.Open(path)
	if err != nil { return 0, fmt.Errorf("acilamadi: %w", err) }
	defer func() { f.Close(); fmt.Println("Kapatildi") }()
	sc := bufio.NewScanner(f); sum := 0; line := 0
	for sc.Scan() {
		line++
		t := strings.TrimSpace(sc.Text())
		if t == "" { continue }
		n, err := strconv.Atoi(t)
		if err != nil { return 0, &ParseError{line, t, err} }
		sum += n
	}
	return sum, sc.Err()
}
func main() {
	defer func() { if r := recover(); r != nil { fmt.Printf("Panik: %v\n", r) } }()
	s, err := topla("sayilar.txt")
	if err != nil {
		var pe *ParseError
		switch {
		case errors.As(err, &pe): fmt.Printf("Parse: %v\n", pe)
		case errors.Is(err, os.ErrNotExist): fmt.Println("Dosya yok")
		default: fmt.Printf("Hata: %v\n", err)
		}
		return
	}
	fmt.Printf("Toplam: %d\n", s)
}

