def binary_search(dizi, hedef):
    sol, sag = 0, len(dizi) - 1
    while sol <= sag:
        orta = (sol + sag) // 2
        if dizi[orta] == hedef:
            return orta
        elif dizi[orta] < hedef:
            sol = orta + 1
        else:
            sag = orta - 1
    return -1

def linear_search(dizi, hedef):
    for i, eleman in enumerate(dizi):
        if eleman == hedef:
            return i
    return -1

def bubble_sort(dizi):
    dizi = dizi[:]
    n = len(dizi)
    for i in range(n):
        for j in range(0, n - i - 1):
            if dizi[j] > dizi[j + 1]:
                dizi[j], dizi[j + 1] = dizi[j + 1], dizi[j]
    return dizi

def selection_sort(dizi):
    dizi = dizi[:]
    n = len(dizi)
    for i in range(n):
        min_idx = i
        for j in range(i + 1, n):
            if dizi[j] < dizi[min_idx]:
                min_idx = j
        dizi[i], dizi[min_idx] = dizi[min_idx], dizi[i]
    return dizi

def tekrar_eden_bul(dizi):
