def sure_olc(func):
    def wrapper(*args, **kwargs):
        basla = time.time()
        sonuc = func(*args, **kwargs)
        bitis = time.time()
        print(f'{func.__name__} {bitis - basla:.4f} saniye surdu')
        return sonuc
    return wrapper

