Tree, hiyerarsik bir veri yapisidir. Bir kok (root) ve ondan dallanan alt dugumlerden olusur:

class Dugum:
    def __init__(self, deger):
        self.deger = deger
        self.sol = None
        self.sag = None

# Ikili Arama Agaci (Binary Search Tree)
class BST:
    def __init__(self):
        self.kok = None

    def ekle(self, deger):
        if not self.kok:
            self.kok = Dugum(deger)
        else:
            self._ekle(self.kok, deger)

    def _ekle(self, dugum, deger):
        if deger < dugum.deger:
            if dugum.sol:
                self._ekle(dugum.sol, deger)
            else:
                dugum.sol = Dugum(deger)
        else:
            if dugum.sag:
                self._ekle(dugum.sag, deger)
            else:
                dugum.sag = Dugum(deger)

    def ara(self, deger):
        return self._ara(self.kok, deger)

    def _ara(self, dugum, deger):
        if not dugum or dugum.deger == deger:
            return dugum
        if deger < dugum.deger:
            return self._ara(dugum.sol, deger)
        return self._ara(dugum.sag, deger)

# Kullanim: Dosya sistemi, HTML DOM, veritabani index'leri
# Terimler: Kok (root), yaprak (leaf), derinlik (depth), dugum (node)

