public class Fibonacci {
  public static void fibonacciYazdir(int adet) {
    int sayi1 = 0, sayi2 = 1;
    System.out.print(sayi1 + " " + sayi2);
    for (int index = 2; index < adet; index++) {
      int sonraki = sayi1 + sayi2;
      System.out.print(" " + sonraki);
      sayi1 = sayi2;
      sayi2 = sonraki;
    }
    System.out.println();
  }

  public static void main(String[] args) {
    int terimSayisi = 8;
    fibonacciYazdir(terimSayisi);
  }
}

