        console.log('Henuz not yok.');
        return;
    }
    notlar.forEach((n, i) => {
        console.log(`${i+1}. ${n.baslik} - ${n.tarih}`);
        console.log(`   ${n.icerik}`);
    });
}

function notSil() {
    notlariListele();
    const no = prompt('Silinecek not no:');
    let notlar = JSON.parse(localStorage.getItem('notlar') || '[]');
    if (no > 0 && no <= notlar.length) {
        notlar.splice(no - 1, 1);
        localStorage.setItem('notlar', JSON.stringify(notlar));
