    const input = document.getElementById('gorevInput');
    if (!input.value.trim()) return;
    gorevler.push({ metin: input.value, tamam: false });
    localStorage.setItem('gorevler', JSON.stringify(gorevler));
    input.value = '';
    listeyiGuncelle();
}

function listeyiGuncelle() {
    const liste = document.getElementById('gorevListesi');
    liste.innerHTML = gorevler.map((g, i) =>
        `<li onclick="gorevTamamla(${i})" style="text-decoration:${g.tamam ? 'line-through' : 'none'}">
