function hesapla(islem) {
    const s1 = parseFloat(document.getElementById('sayi1').value);
    const s2 = parseFloat(document.getElementById('sayi2').value);
    let sonuc;

    switch(islem) {
        case '+':
            sonuc = s1 + s2;
            break;
        case '-':
            sonuc = s1 - s2;
            break;
        case '*':
            sonuc = s1 * s2;
            break;
        case '/':
            sonuc = s2 !== 0 ? s1 / s2 : 'Hata: Sifira bolunmez';
            break;
        default:
            sonuc = 'Gecersiz islem';
    }
    document.getElementById('sonuc').textContent = `Sonuc: ${sonuc}`;
