import (
	"bufio"
	"fmt"
	"os"
)

func main() {
	scanner := bufio.NewScanner(os.Stdin)
	for {
		fmt.Println("\n1-Dosya Yaz 2-Dosya Oku 3-Metin Ekle 4-Cikis")
		fmt.Print("Secim: ")
		scanner.Scan()

		switch scanner.Text() {
		case "1":
			fmt.Print("Dosya adi: ")
			scanner.Scan()
			dosyaAdi := scanner.Text()
			fmt.Print("Icerik: ")
			scanner.Scan()
			os.WriteFile(dosyaAdi, []byte(scanner.Text()+"\n"), 0644)
			fmt.Println("Dosya kaydedildi.")

		case "2":
			fmt.Print("Dosya adi: ")
			scanner.Scan()
			data, hata := os.ReadFile(scanner.Text())
			if hata != nil {
				fmt.Println("Hata:", hata)
			} else {
				fmt.Print(string(data))
			}

		case "3":
			fmt.Print("Dosya adi: ")
			scanner.Scan()
			dosyaAdi := scanner.Text()
			fmt.Print("Eklenecek metin: ")
			scanner.Scan()
			dosya, hata := os.OpenFile(dosyaAdi, os.O_APPEND|os.O_WRONLY, 0644)
			if hata != nil {
				fmt.Println("Hata:", hata)
			} else {
				dosya.WriteString(scanner.Text() + "\n")
				dosya.Close()
				fmt.Println("Metin eklendi.")
			}

		case "4":
			return
		}
	}
}

