public class TaxCalculator {
    private static final double TAX_RATE_TIER1 = 0.15;
    private static final double TAX_RATE_TIER2 = 0.20;
    private static final double TAX_RATE_TIER3 = 0.27;
    private static final double TAX_RATE_TIER4 = 0.35;

    private static final double TIER1_LIMIT = 32000;
    private static final double TIER2_LIMIT = 70000;
    private static final double TIER3_LIMIT = 250000;

    private static final double TIER2_BASE_TAX = 4800;
    private static final double TIER3_BASE_TAX = 12400;
    private static final double TIER4_BASE_TAX = 61000;

    public double calculate(double income) {
        if (income <= TIER1_LIMIT) {
            return income * TAX_RATE_TIER1;
        }
        if (income <= TIER2_LIMIT) {
            return TIER2_BASE_TAX + (income - TIER1_LIMIT) * TAX_RATE_TIER2;
        }
        if (income <= TIER3_LIMIT) {
            return TIER3_BASE_TAX + (income - TIER2_LIMIT) * TAX_RATE_TIER3;
        }
        return TIER4_BASE_TAX + (income - TIER3_LIMIT) * TAX_RATE_TIER4;
    }
}

