function isValidUser(user: RawUser): boolean {
    return !!user.email
        && user.email.includes('@')
        && user.age >= 18;
}

function toProcessedUser(user: RawUser): ProcessedUser {
    return {
        fullName: `${user.firstName} ${user.lastName}`,
        email: user.email.toLowerCase(),
        isAdult: true,
