import heapq
def dijkstra(g,bas):
  m={n:float('inf')for n in g};m[bas]=0
  pq=[(0,bas)]
  while pq:
    d,n=heapq.heappop(pq)
    if d>m[n]:continue
    for k,v in g[n].items():
      nd=d+v
      if nd<m[k]:m[k]=nd;heapq.heappush(pq,(nd,k))
  return m
g={'A':{'B':1,'C':4},'B':{'C':2,'D':5},'C':{'D':1},'D':{}}
print(dijkstra(g,'A'))

def lcs(a,b):
  m,n=len(a),len(b)
  dp=[[0]*(n+1)for _ in range(m+1)]
  for i in range(1,m+1):
    for j in range(1,n+1):
      if a[i-1]==b[j-1]:dp[i][j]=1+dp[i-1][j-1]
      else:dp[i][j]=max(dp[i-1][j],dp[i][j-1])
  return dp[m][n]
print(lcs('ABCDGH','AEDFHR'))

def knapsack(W,wt,val,n):
  dp=[[0]*(W+1)for _ in range(n+1)]
  for i in range(1,n+1):
    for w in range(1,W+1):
      if wt[i-1]<=w:dp[i][w]=max(val[i-1]+dp[i-1][w-wt[i-1]],dp[i-1][w])
      else:dp[i][w]=dp[i-1][w]
  return dp[n][W]
val=[60,100,120];wt=[10,20,30];W=50
print(knapsack(W,wt,val,len(val)))

def selection_sort(arr):
  for i in range(len(arr)):
    m=i
    for j in range(i+1,len(arr)):
      if arr[j]<arr[m]:m=j
    arr[i],arr[m]=arr[m],arr[i]
  return arr
print(selection_sort([64,25,12,22,11]))

def bubble_sort(arr):
  n=len(arr)
  for i in range(n):
    for j in range(0,n-i-1):
      if arr[j]>arr[j+1]:arr[j],arr[j+1]=arr[j+1],arr[j]
  return arr
print(bubble_sort([64,34,25,12,22,11,90]))

