function csvParse(csvMetin, ayirac = ',') {
  if (typeof csvMetin !== 'string') throw new Error('Gecersiz girdi');
  const satirlar = csvMetin.trim().split('\n');
  if (satirlar.length === 0) return [];
  const basliklar = satirlar[0].split(ayirac);
  return satirlar.slice(1).map(satir => {
    const degerler = satir.split(ayirac);
    return basliklar.reduce((nesne, baslik, i) => {
      nesne[baslik.trim()] = degerler[i]?.trim() || '';
      return nesne;
    }, {});
  });
}

response:
describe('csvParse', () => {
  test('normal csv ayristirma', () => {
    const csv = 'ad,yas\nAli,25\nVeli,30';
