    expect(sonuc).toEqual([{ ad: 'Ali', yas: '25' }, { ad: 'Veli', yas: '30' }]);
  });

  test('kenar durumlar', () => {
    expect(csvParse('baslik')).toEqual([]);
    expect(csvParse('')).toEqual([]);
    const ozelAyirac = 'isim|puan\nA|90\nB|80';
    expect(csvParse(ozelAyirac, '|')).toEqual([{ isim: 'A', puan: '90' }, { isim: 'B', puan: '80' }]);
  });

  test('hata durumu', () => {
    expect(() => csvParse(null)).toThrow('Gecersiz girdi');
    expect(() => csvParse(42)).toThrow('Gecersiz girdi');
  });
});

