public class SifreDogrulayici {
    public static boolean gucluMu(String sifre) {
        if (sifre == null) throw new IllegalArgumentException("Sifre null olamaz");
        if (sifre.length() < 8) return false;
        boolean buyuk = false, kucuk = false, rakam = false, ozel = false;
        for (char c : sifre.toCharArray()) {
            if (Character.isUpperCase(c)) buyuk = true;
            else if (Character.isLowerCase(c)) kucuk = true;
            else if (Character.isDigit(c)) rakam = true;
            else ozel = true;
        }
        return buyuk && kucuk && rakam && ozel;
    }
}

