type Yigin struct {
    items []int
}

func (y *Yigin) Ite(item int) {
    y.items = append(y.items, item)
}

func (y *Yigin) Cikar() (int, error) {
    if len(y.items) == 0 {
        return 0, fmt.Errorf("yigin bos")
    }
    son := len(y.items) - 1
    deger := y.items[son]
    y.items = y.items[:son]
    return deger, nil
